import { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';

function Navbar() {
  const navigate = useNavigate();
  const location = useLocation();
  const [open, setOpen] = useState(false);
  const token = localStorage.getItem('token');
  const user = JSON.parse(localStorage.getItem('user') || '{}');

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  const isActive = (path) => location.pathname === path;

  const navLinks = [
    { to: '/home', label: 'HOME' },
    { to: '/home', label: 'EVENTS' },
    { to: '/my-bookings', label: 'COMING SOON' },
    { to: '/my-bookings', label: 'OUR EVENTS' },
    { to: '/my-bookings', label: 'ABOUT' },
  ];

  return (
    <nav style={{
      background: 'rgba(255,255,255,0.05)',
      backdropFilter: 'blur(20px)',
      borderBottom: '1px solid rgba(255,255,255,0.1)',
      position: 'sticky', top: 0, zIndex: 100,
      padding: '0 2rem',
    }}>
      <div style={{ maxWidth: '1400px', margin: '0 auto', display: 'flex', justifyContent: 'space-between', alignItems: 'center', height: '70px' }}>
        
        {/* Logo */}
        <Link to="/home" style={{ display: 'flex', alignItems: 'center', gap: '10px', textDecoration: 'none' }}>
          <div style={{
            background: 'linear-gradient(135deg, #a78bfa, #7c3aed)',
            width: '36px', height: '36px', borderRadius: '10px',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: '18px', fontWeight: 'bold', color: 'white'
          }}>E</div>
          <span style={{ color: 'white', fontWeight: '700', fontSize: '1.2rem', letterSpacing: '1px' }}>
            Event<span style={{ color: '#a78bfa' }}>Ease</span>
          </span>
        </Link>

        {/* Nav Links */}
        <div style={{ display: 'flex', gap: '2rem', alignItems: 'center' }}>
          {navLinks.map(link => (
            <Link key={link.label} to={link.to} style={{
              color: isActive(link.to) ? '#a78bfa' : 'rgba(255,255,255,0.7)',
              textDecoration: 'none', fontSize: '0.75rem', fontWeight: '600',
              letterSpacing: '1px', transition: 'color 0.2s',
              borderBottom: isActive(link.to) ? '2px solid #a78bfa' : '2px solid transparent',
              paddingBottom: '4px'
            }}>
              {link.label}
            </Link>
          ))}
        </div>

        {/* Right Side */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          {token ? (
            <>
              {user.role === 'admin' && (
                <Link to="/admin" style={{
                  background: 'rgba(167,139,250,0.2)', color: '#a78bfa',
                  padding: '8px 16px', borderRadius: '8px', textDecoration: 'none',
                  fontSize: '0.8rem', fontWeight: '600', border: '1px solid rgba(167,139,250,0.3)'
                }}>Admin Panel</Link>
              )}
              <span style={{
                background: 'rgba(255,255,255,0.1)', color: 'white',
                padding: '8px 16px', borderRadius: '20px', fontSize: '0.8rem', fontWeight: '500'
              }}>👤 {user.name}</span>
              <button onClick={handleLogout} style={{
                background: 'linear-gradient(135deg, #ef4444, #dc2626)',
                color: 'white', border: 'none', padding: '8px 20px',
                borderRadius: '20px', cursor: 'pointer', fontSize: '0.8rem', fontWeight: '600'
              }}>Logout</button>
            </>
          ) : (
            <>
              <Link to="/login" style={{ color: 'rgba(255,255,255,0.8)', textDecoration: 'none', fontSize: '0.85rem' }}>Login</Link>
              <Link to="/register" style={{
                background: 'linear-gradient(135deg, #7c3aed, #a78bfa)',
                color: 'white', padding: '8px 20px', borderRadius: '20px',
                textDecoration: 'none', fontSize: '0.85rem', fontWeight: '600'
              }}>Sign Up</Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}
export default Navbar;
